26: /**
27:  * All tcp external authorization stats. @see stats_macros.h
28:  */
29: #define ALL_TCP_EXT_AUTHZ_STATS(COUNTER, GAUGE)                                                    \
30:   COUNTER(cx_closed)                                                                               \
31:   COUNTER(denied)                                                                                  \
32:   COUNTER(error)                                                                                   \
33:   COUNTER(failure_mode_allowed)                                                                    \
34:   COUNTER(ok)                                                                                      \
35:   COUNTER(total)                                                                                   \
36:   COUNTER(disabled)                                                                                \
37:   GAUGE(active, Accumulate)
38: 
39: /**
40:  * Struct definition for all external authorization stats. @see stats_macros.h
41:  */
42: struct InstanceStats {
43:   ALL_TCP_EXT_AUTHZ_STATS(GENERATE_COUNTER_STRUCT, GENERATE_GAUGE_STRUCT)
44: };
45: 
46: /**
47:  * Global configuration for ExtAuthz filter.
48:  */
49: class Config {
50:   using LabelsMap = Protobuf::Map<std::string, std::string>;
51: 
52: public:
53:   Config(const envoy::extensions::filters::network::ext_authz::v3::ExtAuthz& config,
54:          Stats::Scope& scope, Server::Configuration::ServerFactoryContext& context)
55:       : stats_(generateStats(config.stat_prefix(), scope)),
56:         failure_mode_allow_(config.failure_mode_allow()),
57:         include_peer_certificate_(config.include_peer_certificate()),
58:         include_tls_session_(config.include_tls_session()),
59:         filter_enabled_metadata_(
60:             config.has_filter_enabled_metadata()
61:                 ? absl::optional<Matchers::MetadataMatcher>(
62:                       Matchers::MetadataMatcher(config.filter_enabled_metadata(), context))
63:                 : absl::nullopt) {
64:     auto labels_key_it =
65:         context.bootstrap().node().metadata().fields().find(config.bootstrap_metadata_labels_key());
66:     if (labels_key_it != context.bootstrap().node().metadata().fields().end()) {
67:       for (const auto& labels_it : labels_key_it->second.struct_value().fields()) {
68:         destination_labels_[labels_it.first] = labels_it.second.string_value();
69:       }
70:     }
71:   }
72: 
73:   const InstanceStats& stats() { return stats_; }
74:   bool failureModeAllow() const { return failure_mode_allow_; }
75:   void setFailModeAllow(bool value) { failure_mode_allow_ = value; }
76:   bool includePeerCertificate() const { return include_peer_certificate_; }
77:   bool includeTLSSession() const { return include_tls_session_; }
78:   const LabelsMap& destinationLabels() const { return destination_labels_; }
79:   bool filterEnabledMetadata(const envoy::config::core::v3::Metadata& metadata) const {
80:     return filter_enabled_metadata_.has_value() ? filter_enabled_metadata_->match(metadata) : true;
81:   }
82: 
83: private:
84:   static InstanceStats generateStats(const std::string& name, Stats::Scope& scope);
85:   const InstanceStats stats_;
86:   bool failure_mode_allow_;
87:   LabelsMap destination_labels_;
88:   const bool include_peer_certificate_;
89:   const bool include_tls_session_;
90:   const absl::optional<Matchers::MetadataMatcher> filter_enabled_metadata_;
91: };
92: 
93: using ConfigSharedPtr = std::shared_ptr<Config>;
94: 
95: /**
96:  * ExtAuthz filter instance. This filter will call the Authorization service with the given
97:  * configuration parameters. If the authorization service returns an error or a deny the
98:  * connection will be closed without any further filters being called. Otherwise all buffered
99:  * data will be released to further filters.
100:  */
101: class Filter : public Network::ReadFilter,
102:                public Network::ConnectionCallbacks,
103:                public Filters::Common::ExtAuthz::RequestCallbacks {
104:   using LabelsMap = std::map<std::string, std::string>;
105: 
106: public:
107:   Filter(ConfigSharedPtr config, Filters::Common::ExtAuthz::ClientPtr&& client)
108:       : config_(config), client_(std::move(client)) {}
109:   ~Filter() override = default;
110: 
111:   // Network::ReadFilter
112:   Network::FilterStatus onData(Buffer::Instance& data, bool end_stream) override;
113:   Network::FilterStatus onNewConnection() override;
114:   void initializeReadFilterCallbacks(Network::ReadFilterCallbacks& callbacks) override {
115:     filter_callbacks_ = &callbacks;
116:     filter_callbacks_->connection().addConnectionCallbacks(*this);
117:   }
118: 
119:   // Network::ConnectionCallbacks
120:   void onEvent(Network::ConnectionEvent event) override;
121:   void onAboveWriteBufferHighWatermark() override {}
122:   void onBelowWriteBufferLowWatermark() override {}
123: 
124:   // ExtAuthz::RequestCallbacks
125:   void onComplete(Filters::Common::ExtAuthz::ResponsePtr&&) override;
126: 
127: private:
128:   // State of this filter's communication with the external authorization service.
129:   // The filter has either not started calling the external service, in the middle of calling
130:   // it or has completed.
131:   enum class Status { NotStarted, Calling, Complete };
132:   // FilterReturn is used to capture what the return code should be to the filter chain.
133:   // if this filter is either in the middle of calling the external service or the result is denied
134:   // then the filter chain should stop. Otherwise the filter chain can continue to the next filter.
135:   enum class FilterReturn { Stop, Continue };
136:   void callCheck();
137: 
138:   bool filterEnabled(const envoy::config::core::v3::Metadata& metadata) {
139:     return config_->filterEnabledMetadata(metadata);
140:   }
141:   absl::optional<MonotonicTime> start_time_;
142: 
143:   ConfigSharedPtr config_;
144:   Filters::Common::ExtAuthz::ClientPtr client_;
145:   Network::ReadFilterCallbacks* filter_callbacks_{};
146:   Status status_{Status::NotStarted};
147:   FilterReturn filter_return_{FilterReturn::Stop};
148:   // Used to identify if the callback to onComplete() is synchronous (on the stack) or asynchronous.
149:   bool calling_check_{};
150:   envoy::service::auth::v3::CheckRequest check_request_{};
151: };
