23: Network::FilterFactoryCb ExtAuthzConfigFactory::createFilterFactoryFromProtoTyped(
24:     const envoy::extensions::filters::network::ext_authz::v3::ExtAuthz& proto_config,
25:     Server::Configuration::FactoryContext& context) {
26:   ConfigSharedPtr ext_authz_config =
27:       std::make_shared<Config>(proto_config, context.scope(), context.serverFactoryContext());
28:   const uint32_t timeout_ms = PROTOBUF_GET_MS_OR_DEFAULT(proto_config.grpc_service(), timeout, 200);
29: 
30:   THROW_IF_NOT_OK(Envoy::Config::Utility::checkTransportVersion(proto_config));
31:   return [grpc_service = proto_config.grpc_service(), &context, ext_authz_config,
32:           timeout_ms](Network::FilterManager& filter_manager) -> void {
33:     auto factory_or_error = context.serverFactoryContext()
34:                                 .clusterManager()
35:                                 .grpcAsyncClientManager()
36:                                 .factoryForGrpcService(grpc_service, context.scope(), true);
37:     THROW_IF_STATUS_NOT_OK(factory_or_error, throw);
38:     auto client = std::make_unique<Filters::Common::ExtAuthz::GrpcClientImpl>(
39:         factory_or_error.value()->createUncachedRawAsyncClient(),
40:         std::chrono::milliseconds(timeout_ms));
41:     filter_manager.addReadFilter(Network::ReadFilterSharedPtr{
42:         std::make_shared<Filter>(ext_authz_config, std::move(client))});
43:   };
44: }
