48: void headerMapAddHeader(envoy::config::core::v3::HeaderMap& mutable_header_map,
49:                         const std::string& key, const std::string& value) {
50:   auto* new_header = mutable_header_map.mutable_headers()->Add();
51:   new_header->set_key(key);
52:   new_header->set_raw_value(value);
