55: void CheckRequestUtils::setAttrContextPeer(envoy::service::auth::v3::AttributeContext::Peer& peer,
56:                                            const Network::Connection& connection,
57:                                            const std::string& service, const bool local,
58:                                            bool include_certificate) {
59: 
60:   // Set the address
61:   auto addr = peer.mutable_address();
62:   if (local) {
63:     Envoy::Network::Utility::addressToProtobufAddress(
64:         *connection.connectionInfoProvider().localAddress(), *addr);
65:   } else {
66:     Envoy::Network::Utility::addressToProtobufAddress(
67:         *connection.connectionInfoProvider().remoteAddress(), *addr);
68:   }
69: 
70:   // Set the principal. Preferably the URI SAN, DNS SAN or Subject in that order from the peer's
71:   // cert. Include the X.509 certificate of the source peer, if configured to do so.
72:   auto ssl = connection.ssl();
73:   if (ssl != nullptr) {
74:     if (local) {
75:       const auto uri_sans = ssl->uriSanLocalCertificate();
76:       if (uri_sans.empty()) {
77:         const auto dns_sans = ssl->dnsSansLocalCertificate();
78:         if (dns_sans.empty()) {
79:           peer.set_principal(MessageUtil::sanitizeUtf8String(ssl->subjectLocalCertificate()));
80:         } else {
81:           peer.set_principal(MessageUtil::sanitizeUtf8String(dns_sans[0]));
82:         }
83:       } else {
84:         peer.set_principal(MessageUtil::sanitizeUtf8String(uri_sans[0]));
85:       }
86:     } else {
87:       const auto uri_sans = ssl->uriSanPeerCertificate();
88:       if (uri_sans.empty()) {
89:         const auto dns_sans = ssl->dnsSansPeerCertificate();
90:         if (dns_sans.empty()) {
91:           peer.set_principal(MessageUtil::sanitizeUtf8String(ssl->subjectPeerCertificate()));
92:         } else {
93:           peer.set_principal(MessageUtil::sanitizeUtf8String(dns_sans[0]));
94:         }
95:       } else {
96:         peer.set_principal(MessageUtil::sanitizeUtf8String(uri_sans[0]));
97:       }
98:       if (include_certificate) {
99:         peer.set_certificate(ssl->urlEncodedPemEncodedPeerCertificate());
100:       }
101:     }
102:   }
103: 
104:   if (!service.empty()) {
105:     peer.set_service(MessageUtil::sanitizeUtf8String(service));
106:   }
107: }
