118: void CheckRequestUtils::setRequestTime(envoy::service::auth::v3::AttributeContext::Request& req,
119:                                        const StreamInfo::StreamInfo& stream_info) {
120:   // Set the timestamp when the proxy receives the first byte of the request.
121:   req.mutable_time()->MergeFrom(Protobuf::util::TimeUtil::NanosecondsToTimestamp(
