127: void CheckRequestUtils::setHttpRequest(
128:     envoy::service::auth::v3::AttributeContext::HttpRequest& httpreq, uint64_t stream_id,
129:     const StreamInfo::StreamInfo& stream_info, const Buffer::Instance* decoding_buffer,
130:     const Envoy::Http::RequestHeaderMap& headers, uint64_t max_request_bytes, bool pack_as_bytes,
131:     bool encode_raw_headers, const MatcherSharedPtr& allowed_headers_matcher,
132:     const MatcherSharedPtr& disallowed_headers_matcher) {
133:   httpreq.set_id(std::to_string(stream_id));
134:   httpreq.set_method(getHeaderStr(headers.Method()));
135:   httpreq.set_path(getHeaderStr(headers.Path()));
136:   httpreq.set_host(getHeaderStr(headers.Host()));
137:   httpreq.set_scheme(getHeaderStr(headers.Scheme()));
138:   httpreq.set_size(stream_info.bytesReceived());
139: 
140:   if (stream_info.protocol()) {
141:     httpreq.set_protocol(Envoy::Http::Utility::getProtocolString(stream_info.protocol().value()));
142:   }
143: 
144:   // Fill in the headers.
145:   auto* mutable_headers = !encode_raw_headers ? httpreq.mutable_headers() : nullptr;
146:   // Calling mutable_header_map() creates the field in the request; only do so when necessary.
147:   auto* mutable_header_map = encode_raw_headers ? httpreq.mutable_header_map() : nullptr;
148: 
149:   headers.iterate([encode_raw_headers, allowed_headers_matcher, disallowed_headers_matcher,
150:                    mutable_headers, mutable_header_map](const Envoy::Http::HeaderEntry& e) {
151:     // Skip any client EnvoyAuthPartialBody header, which could interfere with internal use.
152:     if (e.key().getStringView() == Headers::get().EnvoyAuthPartialBody.get()) {
153:       return Envoy::Http::HeaderMap::Iterate::Continue;
154:     }
155: 
156:     const std::string key(e.key().getStringView());
157:     if (disallowed_headers_matcher != nullptr && disallowed_headers_matcher->matches(key)) {
158:       return Envoy::Http::HeaderMap::Iterate::Continue;
159:     }
160: 
161:     if (allowed_headers_matcher != nullptr && !allowed_headers_matcher->matches(key)) {
162:       return Envoy::Http::HeaderMap::Iterate::Continue;
163:     }
164: 
165:     if (encode_raw_headers) {
166:       headerMapAddHeader(*mutable_header_map, key, std::string(e.value().getStringView()));
167:     } else {
168:       const std::string sanitized_value =
169:           MessageUtil::sanitizeUtf8String(e.value().getStringView());
170: 
171:       if (mutable_headers->find(key) == mutable_headers->end()) {
172:         (*mutable_headers)[key] = sanitized_value;
173:       } else {
174:         // Merge duplicate headers.
175:         (*mutable_headers)[key].append(",").append(sanitized_value);
176:       }
177:     }
178:     return Envoy::Http::HeaderMap::Iterate::Continue;
179:   });
180: 
181:   // Set request body.
182:   if (max_request_bytes > 0 && decoding_buffer != nullptr) {
183:     const uint64_t length = std::min(decoding_buffer->length(), max_request_bytes);
184:     std::string data(length, 0);
185:     decoding_buffer->copyOut(0, length, &data[0]);
186: 
187:     // This pack_as_bytes flag allows us to switch the content type (bytes or string) of "body" to
188:     // be sent to the external authorization server without doing string encoding check (in this
189:     // case UTF-8 check).
190:     if (pack_as_bytes) {
191:       httpreq.set_raw_body(std::move(data));
192:     } else {
193:       httpreq.set_body(MessageUtil::sanitizeUtf8String(data));
194:     }
195: 
196:     // Add in a header to detect when a partial body is used.
197:     std::string partial_body_value;
198:     if (length != decoding_buffer->length()) {
199:       partial_body_value = "true";
200:     } else {
201:       partial_body_value = "false";
202:     }
203:     if (encode_raw_headers) {
204:       headerMapAddHeader(*mutable_header_map, Headers::get().EnvoyAuthPartialBody.get(),
205:                          partial_body_value);
206:     } else {
207:       (*mutable_headers)[Headers::get().EnvoyAuthPartialBody.get()] = std::move(partial_body_value);
208:     }
209:   }
210: }
