212: void CheckRequestUtils::setAttrContextRequest(
213:     envoy::service::auth::v3::AttributeContext::Request& req, const uint64_t stream_id,
214:     const StreamInfo::StreamInfo& stream_info, const Buffer::Instance* decoding_buffer,
215:     const Envoy::Http::RequestHeaderMap& headers, uint64_t max_request_bytes, bool pack_as_bytes,
216:     bool encode_raw_headers, const MatcherSharedPtr& allowed_headers_matcher,
217:     const MatcherSharedPtr& disallowed_headers_matcher) {
218:   setRequestTime(req, stream_info);
219:   setHttpRequest(*req.mutable_http(), stream_id, stream_info, decoding_buffer, headers,
220:                  max_request_bytes, pack_as_bytes, encode_raw_headers, allowed_headers_matcher,
221:                  disallowed_headers_matcher);
