237: void CheckRequestUtils::createHttpCheck(
238:     const Envoy::Http::StreamDecoderFilterCallbacks* callbacks,
239:     const Envoy::Http::RequestHeaderMap& headers,
240:     Protobuf::Map<std::string, std::string>&& context_extensions,
241:     envoy::config::core::v3::Metadata&& metadata_context,
242:     envoy::config::core::v3::Metadata&& route_metadata_context,
243:     envoy::service::auth::v3::CheckRequest& request, uint64_t max_request_bytes, bool pack_as_bytes,
244:     bool encode_raw_headers, bool include_peer_certificate, bool include_tls_session,
245:     const Protobuf::Map<std::string, std::string>& destination_labels,
246:     const MatcherSharedPtr& allowed_headers_matcher,
247:     const MatcherSharedPtr& disallowed_headers_matcher) {
248: 
249:   auto attrs = request.mutable_attributes();
250:   const std::string service = getHeaderStr(headers.EnvoyDownstreamServiceCluster());
251: 
252:   // *cb->connection(), callbacks->streamInfo() and callbacks->decodingBuffer() are not qualified as
253:   // const.
254:   auto* cb = const_cast<Envoy::Http::StreamDecoderFilterCallbacks*>(callbacks);
255: 
256:   setAttrContextPeer(*attrs->mutable_source(), *cb->connection(), service, false,
257:                      include_peer_certificate);
258:   setAttrContextPeer(*attrs->mutable_destination(), *cb->connection(), EMPTY_STRING, true,
259:                      include_peer_certificate);
260:   setAttrContextRequest(*attrs->mutable_request(), cb->streamId(), cb->streamInfo(),
261:                         cb->decodingBuffer(), headers, max_request_bytes, pack_as_bytes,
262:                         encode_raw_headers, allowed_headers_matcher, disallowed_headers_matcher);
263: 
264:   if (include_tls_session) {
265:     setTLSSession(*attrs->mutable_tls_session(), *cb->connection());
266:   }
267:   (*attrs->mutable_destination()->mutable_labels()) = destination_labels;
268:   // Fill in the context extensions and metadata context.
269:   (*attrs->mutable_context_extensions()) = std::move(context_extensions);
270:   (*attrs->mutable_metadata_context()) = std::move(metadata_context);
271:   (*attrs->mutable_route_metadata_context()) = std::move(route_metadata_context);
272: }
