306: void RawHttpClientImpl::onBeforeFinalizeUpstreamSpan(
307:     Tracing::Span& span, const Http::ResponseHeaderMap* response_headers) {
308:   if (response_headers != nullptr) {
309:     const uint64_t status_code = Http::Utility::getResponseStatus(*response_headers);
310:     span.setTag(TracingConstants::get().HttpStatus,
311:                 Http::CodeUtility::toString(static_cast<Http::Code>(status_code)));
312:     span.setTag(TracingConstants::get().TraceStatus, status_code == enumToInt(Http::Code::OK)
313:                                                          ? TracingConstants::get().TraceOk
314:                                                          : TracingConstants::get().TraceUnauthz);
315:   }
316: }
317: 
318: ResponsePtr RawHttpClientImpl::toResponse(Http::ResponseMessagePtr message) {
319:   const uint64_t status_code = Http::Utility::getResponseStatus(message->headers());
320: 
321:   // Set an error status if the call to the authorization server returns any of the 5xx HTTP error
322:   // codes. A Forbidden response is sent to the client if the filter has not been configured with
323:   // failure_mode_allow.
324:   if (Http::CodeUtility::is5xx(status_code)) {
325:     return std::make_unique<Response>(errorResponse());
326:   }
327: 
328:   // Extract headers-to-remove from the storage header coming from the
329:   // authorization server.
330:   const auto& storage_header_name = Headers::get().EnvoyAuthHeadersToRemove;
331:   // If we are going to construct an Ok response we need to save the
332:   // headers_to_remove in a variable first.
333:   std::vector<std::string> headers_to_remove;
334:   if (status_code == enumToInt(Http::Code::OK)) {
335:     const auto& get_result = message->headers().get(storage_header_name);
336:     for (size_t i = 0; i < get_result.size(); ++i) {
337:       const Http::HeaderEntry* entry = get_result[i];
338:       if (entry != nullptr) {
339:         absl::string_view storage_header_value = entry->value().getStringView();
340:         std::vector<absl::string_view> header_names = StringUtil::splitToken(
341:             storage_header_value, ",", /*keep_empty_string=*/false, /*trim_whitespace=*/true);
342:         headers_to_remove.reserve(headers_to_remove.size() + header_names.size());
343:         for (const auto& header_name : header_names) {
344:           headers_to_remove.emplace_back(header_name);
345:         }
346:       }
347:     }
348:   }
349:   // Now remove the storage header from the authz server response headers before
350:   // we reuse them to construct an Ok/Denied authorization response below.
351:   message->headers().remove(storage_header_name);
352: 
353:   // Create an Ok authorization response.
354:   if (status_code == enumToInt(Http::Code::OK)) {
355:     SuccessResponse ok{message->headers(),
356:                        config_->upstreamHeaderMatchers(),
357:                        config_->upstreamHeaderToAppendMatchers(),
358:                        config_->clientHeaderOnSuccessMatchers(),
359:                        config_->dynamicMetadataMatchers(),
360:                        Response{CheckStatus::OK,
361:                                 UnsafeHeaderVector{},
362:                                 UnsafeHeaderVector{},
363:                                 UnsafeHeaderVector{},
364:                                 UnsafeHeaderVector{},
365:                                 UnsafeHeaderVector{},
366:                                 UnsafeHeaderVector{},
367:                                 UnsafeHeaderVector{},
368:                                 std::move(headers_to_remove),
369:                                 Http::Utility::QueryParamsVector{},
370:                                 {},
371:                                 EMPTY_STRING,
372:                                 Http::Code::OK,
373:                                 ProtobufWkt::Struct{}}};
374:     return std::move(ok.response_);
375:   }
376: 
377:   // Create a Denied authorization response.
378:   SuccessResponse denied{message->headers(),
379:                          config_->clientHeaderMatchers(),
380:                          config_->upstreamHeaderToAppendMatchers(),
381:                          config_->clientHeaderOnSuccessMatchers(),
382:                          config_->dynamicMetadataMatchers(),
383:                          Response{CheckStatus::Denied,
384:                                   UnsafeHeaderVector{},
385:                                   UnsafeHeaderVector{},
386:                                   UnsafeHeaderVector{},
387:                                   UnsafeHeaderVector{},
388:                                   UnsafeHeaderVector{},
389:                                   UnsafeHeaderVector{},
390:                                   UnsafeHeaderVector{},
391:                                   {{}},
392:                                   Http::Utility::QueryParamsVector{},
393:                                   {},
394:                                   message->bodyAsString(),
395:                                   static_cast<Http::Code>(status_code),
396:                                   ProtobufWkt::Struct{}}};
397:   return std::move(denied.response_);
398: }
